import{_ as s,o as a,c as e,a as p}from"./chunks/framework.8tiMeCK-.js";const u=JSON.parse('{"title":"1.8  看见差异——生产内核与调试内核的配置对决","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch01_8.md","filePath":"notes/linux_kernel_debugging/ch01_8.md","lastUpdated":null}'),i={name:"notes/linux_kernel_debugging/ch01_8.md"};function l(c,n,d,o,t,r){return a(),e("div",null,[...n[0]||(n[0]=[p(`<h1 id="_1-8-看见差异——生产内核与调试内核的配置对决" tabindex="-1">1.8 看见差异——生产内核与调试内核的配置对决 <a class="header-anchor" href="#_1-8-看见差异——生产内核与调试内核的配置对决" aria-label="Permalink to &quot;1.8  看见差异——生产内核与调试内核的配置对决&quot;">​</a></h1><p>上一节我们把调试内核里能开的开关都打开了——这很好，但这也引来了一个问题：我们到底改了什么？或者说，这一堆 <code>y</code> 和 <code>n</code> 的跳动，到底让这颗内核和它的生产版兄弟产生了多大的分歧？</p><p>这个问题比你想象的要重要。如果你不清楚两者的边界，将来调试的时候，你可能会把一个「只有调试内核才有的 Bug」当成通用 Bug 来修，或者更糟——在生产环境里试图加载一个只有调试符号才存在的模块。</p><p>让我们把看不见的变成看得见的。</p><h3 id="对比配置的显微镜-diffconfig" tabindex="-1">对比配置的显微镜：<code>diffconfig</code> <a class="header-anchor" href="#对比配置的显微镜-diffconfig" aria-label="Permalink to &quot;对比配置的显微镜：\`diffconfig\`&quot;">​</a></h3><p>内核源码树里藏着一个很好用的脚本，叫 <code>scripts/diffconfig</code>。它就像是一台显微镜，专门用来对比两份 <code>.config</code> 文件，并把差异放大给你看。</p><p>现在，假设我们手上有两份配置文件路径：</p><ul><li>生产内核配置：<code>~/lkd_kernels/kconfig_prod01</code></li><li>调试内核配置：<code>~/lkd_kernels/kconfig_dbg01</code></li></ul><p>我们在调试内核的源码目录下执行这个脚本，把差异输出到一个文本文件里：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scripts/diffconfig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels/kconfig_prod01</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/lkd_kernels/kconfig_dbg01</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ../../kconfig_diff_prod_to_debug.txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一行命令跑完，你就拥有了一份完整的「体检报告」。</p><p>在我的系统上，这份报告超过了 200 行。这意味着调试内核并不是「稍微」改了一下，而是发生了<strong>基因层面的突变</strong>。</p><h3 id="解读差异报告" tabindex="-1">解读差异报告 <a class="header-anchor" href="#解读差异报告" aria-label="Permalink to &quot;解读差异报告&quot;">​</a></h3><p>用编辑器打开 <code>kconfig_diff_prod_to_debug.txt</code>。你会发现文件里的行被分成了三类，每一类都在讲一个不同的故事。</p><h4 id="第一类-被移除的功能-前缀" tabindex="-1">第一类：被移除的功能（前缀 <code>-</code>） <a class="header-anchor" href="#第一类-被移除的功能-前缀" aria-label="Permalink to &quot;第一类：被移除的功能（前缀 \`-\`）&quot;">​</a></h4><p>以 <code>-</code> 开头的行，代表这些功能在生产内核里是有的，但在调试内核里被我们剔除了。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-BPF_LSM y</span></span>
<span class="line"><span>-DEFAULT_SECURITY_APPARMOR y</span></span>
<span class="line"><span>-DEFAULT_SECURITY_SELINUX n</span></span>
<span class="line"><span>-DEFAULT_SECURITY_SMACK n</span></span>
<span class="line"><span>[ … ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>看到这个列表你可能会愣一下：<strong>等等，调试内核为什么要把安全模块关掉？</strong></p><p>这听起来很反直觉，但这里有个很实际的权衡。某些安全机制（比如 LSM 框架下的某些模块）会对系统调用进行深度拦截，这会极大地拖慢系统速度，甚至干扰调试器的正常追踪。在专门用来抓 Bug 的内核上，为了性能和纯粹性，有时候不得不暂时卸下这些盾牌。</p><h4 id="第二类-被修改的开关-n-y-或-y-n" tabindex="-1">第二类：被修改的开关（<code>n -&gt; y</code> 或 <code>y -&gt; n</code>） <a class="header-anchor" href="#第二类-被修改的开关-n-y-或-y-n" aria-label="Permalink to &quot;第二类：被修改的开关（\`n -&gt; y\` 或 \`y -&gt; n\`）&quot;">​</a></h4><p>这是最核心的部分。这里显示的是那些「状态发生翻转」的选项。你会发现，绝大多数箭头都是指向 <code>y</code> 的。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>DEBUG_ATOMIC_SLEEP n -&gt; y</span></span>
<span class="line"><span>DEBUG_BOOT_PARAMS n -&gt; y</span></span>
<span class="line"><span>DEBUG_INFO n -&gt; y</span></span>
<span class="line"><span>DEBUG_KMEMLEAK n -&gt; y</span></span>
<span class="line"><span>DEBUG_LOCK_ALLOC n -&gt; y</span></span>
<span class="line"><span>DEBUG_MUTEXES n -&gt; y</span></span>
<span class="line"><span>DEBUG_PLIST n -&gt; y</span></span>
<span class="line"><span>DEBUG_RT_MUTEXES n -&gt; y</span></span>
<span class="line"><span>DEBUG_RWSEMS n -&gt; y</span></span>
<span class="line"><span>DEBUG_SPINLOCK n -&gt; y</span></span>
<span class="line"><span>[ … ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>每一行 <code>n -&gt; y</code> 都意味着我们在调试内核里埋下了一双眼睛。</p><ul><li><code>DEBUG_ATOMIC_SLEEP</code>：原本不许在原子上下文睡觉，现在不仅不许，还会大喊大叫。</li><li><code>DEBUG_INFO</code>：原本为了节省空间不给符号，现在全给，为了 gdb 能看懂。</li><li><code>DEBUG_LOCK_ALLOC</code>、<code>DEBUG_MUTEXES</code>、<code>DEBUG_SPINLOCK</code>：锁相关的检查全开。</li></ul><p>在这里，你也看到了我们之前特意修改的名字后缀：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>LKDTM n -&gt; m</span></span>
<span class="line"><span>LOCALVERSION &quot;-prod01&quot; -&gt; &quot;-dbg01&quot;</span></span>
<span class="line"><span>LOCK_STAT n -&gt; y</span></span>
<span class="line"><span>MMIOTRACE n -&gt; y</span></span>
<span class="line"><span>MODULE_SIG y -&gt; n</span></span>
<span class="line"><span>[ … ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ul><li><code>LOCALVERSION</code> 从 <code>-prod01</code> 变成了 <code>-dbg01</code>。这正是为什么你在启动信息里能看到 <code>5.10.17-dbg01</code> 而不是 <code>5.10.17-prod01</code>。</li><li><code>MODULE_SIG</code> 从 <code>y</code> 变成了 <code>n</code>。这里有一个微妙的点：生产内核通常要求模块签名（<code>y</code>），防止加载恶意模块；但调试内核为了方便自己折腾测试模块，通常把强制签名关掉（<code>n</code>），否则你自己写个测试模块加载还得折腾签名证书，简直是给自己找罪受。</li></ul><h4 id="第三类-新增的功能-前缀" tabindex="-1">第三类：新增的功能（前缀 <code>+</code>） <a class="header-anchor" href="#第三类-新增的功能-前缀" aria-label="Permalink to &quot;第三类：新增的功能（前缀 \`+\`）&quot;">​</a></h4><p>以 <code>+</code> 开头的行，代表这些是全新的、在生产内核配置里压根不存在的项目。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>+ARCH_HAS_EARLY_DEBUG y</span></span>
<span class="line"><span>+BITFIELD_KUNIT n</span></span>
<span class="line"><span>[ … ]</span></span>
<span class="line"><span>+IKCONFIG m</span></span>
<span class="line"><span>+KASAN_GENERIC y</span></span>
<span class="line"><span>[ … ]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>注意最后那个 <code>KASAN_GENERIC</code>。这是 <strong>Kernel Address SANitizer</strong>，这是内核调试里的大杀器，专门用来发现内存越界和「释放后使用」这类烂内存 Bug。它会极大地拖慢系统速度（可能让系统慢 2 倍甚至更多），所以在生产内核里它绝对是个禁项，但在调试内核里，它是无价之宝。</p><h3 id="回到现实-你的项目可能不一样" tabindex="-1">回到现实：你的项目可能不一样 <a class="header-anchor" href="#回到现实-你的项目可能不一样" aria-label="Permalink to &quot;回到现实：你的项目可能不一样&quot;">​</a></h3><p>虽然这里我们演示了一种「标准」的生产 vs 调试的配对方式，但我必须诚实地说：</p><blockquote><p>特定的内核配置只是代表性的。</p></blockquote><p>你的项目或产品可能有一大堆奇葩需求。也许你的生产内核需要某些特殊的实时补丁，也许你的调试环境需要跑在一个奇怪的虚拟化平台上。</p><p>另外，如果你是在做现代的嵌入式 Linux，你大概率不是在命令行里敲 <code>make menuconfig</code>，而是在用 <strong>Yocto</strong> 或者 <strong>Buildroot</strong> 这种重量级构建系统。</p><p>如果是那样，你刚才学的这些「手动修改 .config」的功夫就要换个地方用了。在 Yocto 里，你通常得写一个 <code>bbappend</code> 的 recipe 文件来把你的调试配置塞进去。那是一个更复杂的坑，但核心逻辑是一样的：一个是瘦身的运动员，一个是浑身贴满传感器的实验体。</p><h3 id="最终检查" tabindex="-1">最终检查 <a class="header-anchor" href="#最终检查" aria-label="Permalink to &quot;最终检查&quot;">​</a></h3><p>说到这里，我隐秘地希望你已经老实照做了——也就是说，你现在手里应该真的有两颗编译好的内核：一颗生产，一颗调试。</p><p>如果没有，我真的建议你现在就去把编译这一步跑完。不要只看不练。</p><p>如果一切顺利，你现在应该拥有了定制的 5.10 LTS 生产内核和调试内核，随时准备上战场。接下来的章节里，我们就会真的让它们跑起来，看看它们在出问题的时候到底有什么不一样表现。</p><p>在那之前，让我们先用最后一节的内容，给你装上几件调试用的「贴身装备」。</p>`,42)])])}const g=s(i,[["render",l]]);export{u as __pageData,g as default};
